const PART5_EASY = [
  {id:"p5e1",question:"The annual sales report _____ to all department managers by Friday.",options:["A) distribute","B) distributes","C) will be distributed","D) distributing"],answer:"C",explanation:"'Will be distributed' is correct because the subject 'report' receives the action, requiring the passive voice, and the future time marker 'by Friday' requires the future tense 'will be + past participle'. 'Distribute' is wrong because it is an active base form and cannot follow the singular subject without a modal or auxiliary. 'Distributes' is wrong because it is the active third-person singular present, which does not reflect the passive relationship between the report and the action. 'Distributing' is wrong because it is a present participle that requires an auxiliary verb such as 'is' or 'will be' to form a complete verb phrase.",category:"Grammar"},
  {id:"p5e2",question:"Please submit your expense report _____ the end of the month.",options:["A) until","B) by","C) since","D) during"],answer:"B",explanation:"'By' is correct because it marks a deadline, meaning the report must be submitted no later than the end of the month. 'Until' is wrong because it describes a continuous action that lasts up to a point in time, not a one-time submission deadline. 'Since' is wrong because it marks the starting point of an action or state that continues into the present, which does not fit a future deadline. 'During' is wrong because it describes activity that occurs within a period of time, not a specific point that serves as a cutoff.",category:"Preposition"},
  {id:"p5e3",question:"The new employees _____ their orientation sessions last Monday.",options:["A) attend","B) attending","C) attended","D) will attend"],answer:"C",explanation:"'Attended' is correct because the time expression 'last Monday' signals that the action is completed in the past, requiring the simple past tense. 'Attend' is wrong because it is the base form or present simple, which does not match the past time marker 'last Monday'. 'Attending' is wrong because it is a present participle that requires an auxiliary verb and does not express a simple completed past action. 'Will attend' is wrong because it expresses future intention, which contradicts the past time marker 'last Monday'.",category:"Grammar"},
  {id:"p5e4",question:"Ms. Chen is _____ for all customer inquiries in the East Asia region.",options:["A) responsible","B) responsibility","C) responsibly","D) respond"],answer:"A",explanation:"'Responsible' is correct because the fixed phrase 'be responsible for' requires the adjective 'responsible' after the linking verb 'is'. 'Responsibility' is wrong because it is a noun, and placing a noun after 'is' here would not create the idiomatic phrase needed to express duty. 'Responsibly' is wrong because it is an adverb, which cannot follow a linking verb to describe the subject. 'Respond' is wrong because it is a verb, and the sentence already has the main verb 'is', making a second bare verb grammatically incorrect.",category:"Vocabulary"},
  {id:"p5e5",question:"The conference room is _____ the third floor.",options:["A) at","B) on","C) in","D) above"],answer:"B",explanation:"'On' is correct because English uses 'on' with floor levels, as in 'on the third floor', following standard preposition rules for surfaces and levels. 'At' is wrong because it refers to a specific point or location address, not a floor within a building. 'In' is wrong because it describes being enclosed within a space, and floors are treated as flat surfaces rather than enclosed containers. 'Above' is wrong because it implies the room is higher than the third floor, not located on it.",category:"Preposition"},
  {id:"p5e6",question:"We need to _____ a meeting to discuss the budget cuts.",options:["A) make","B) do","C) schedule","D) take"],answer:"C",explanation:"'Schedule a meeting' is correct because 'schedule' is the standard verb collocating with 'meeting' when arranging a time for it to occur. 'Make' is wrong because while 'make' can collocate with some nouns (make a decision), 'make a meeting' is not idiomatic in standard business English. 'Do' is wrong because 'do' collocates with tasks and activities (do the work), not with formal appointments like meetings. 'Take' is wrong because 'take' does not form a natural collocation with 'meeting' in the sense of arranging one.",category:"Vocabulary"},
  {id:"p5e7",question:"The project deadline has been _____ to next month due to technical issues.",options:["A) extended","B) expanding","C) excess","D) expensive"],answer:"A",explanation:"'Extended' is correct because 'extend a deadline' is the standard collocation meaning to push the end date to a later time, and the passive structure 'has been extended' fits grammatically. 'Expanding' is wrong because 'expand' refers to growing in size or scope, not to moving a deadline to a later date. 'Excess' is wrong because it is a noun or adjective meaning a surplus, which cannot fill a past-participle slot in a passive verb phrase. 'Expensive' is wrong because it is an adjective describing cost, which has no grammatical or semantic connection to what happens to a deadline.",category:"Vocabulary"},
  {id:"p5e8",question:"All employees must wear _____ identification badge while in the building.",options:["A) their","B) them","C) they","D) theirs"],answer:"A",explanation:"'Their' is correct because it is a possessive adjective that modifies the noun 'identification badge', agreeing with the plural antecedent 'all employees'. 'Them' is wrong because it is an object pronoun and cannot modify a noun; it functions as the object of a verb or preposition. 'They' is wrong because it is a subject pronoun and cannot be placed before a noun to show possession. 'Theirs' is wrong because it is a possessive pronoun that stands alone without a following noun, whereas 'badge' requires a modifier, not a standalone pronoun.",category:"Grammar"},
  {id:"p5e9",question:"The company _____ established in 1995 by two software engineers.",options:["A) was","B) is","C) were","D) are"],answer:"A",explanation:"'Was' is correct because the sentence uses the passive voice for a completed past action, and 'the company' is a singular subject requiring the singular past form 'was'. 'Is' is wrong because it is the present tense, which contradicts the past time marker '1995'. 'Were' is wrong because it is the plural past form of 'be', and 'the company' is a singular noun requiring 'was'. 'Are' is wrong because it is the plural present form, which is incorrect for both the past tense context and the singular subject.",category:"Grammar"},
  {id:"p5e10",question:"Customers can contact our support team _____ phone or email.",options:["A) with","B) by","C) for","D) from"],answer:"B",explanation:"'By' is correct because the fixed expressions 'by phone' and 'by email' use 'by' to indicate the means or channel of communication. 'With' is wrong because 'with' indicates accompaniment or an instrument held in hand, not an abstract communication method. 'For' is wrong because 'for' indicates purpose or benefit, not the medium through which communication happens. 'From' is wrong because 'from' indicates a source or origin, not the method used to make contact.",category:"Preposition"},
  {id:"p5e11",question:"The marketing team worked _____ to meet the campaign deadline.",options:["A) hardly","B) hard","C) hardness","D) harder"],answer:"B",explanation:"'Hard' is correct because it functions as an adverb modifying 'worked', meaning they put in great effort, and 'work hard' is the standard idiomatic expression. 'Hardly' is wrong because 'hardly' is an adverb meaning 'almost not at all', which is the opposite of the intended meaning. 'Hardness' is wrong because it is a noun referring to the quality of being hard, and a noun cannot modify a verb. 'Harder' is wrong because it is the comparative form, which requires a point of comparison ('harder than before') not present in this sentence.",category:"Vocabulary"},
  {id:"p5e12",question:"Mr. Tanaka has _____ in the finance department for ten years.",options:["A) work","B) worked","C) working","D) works"],answer:"B",explanation:"'Worked' is correct because the present perfect 'has worked' is used to describe an action that started in the past and continues to the present, matching the time expression 'for ten years'. 'Work' is wrong because the base form cannot follow the auxiliary 'has' to form the present perfect; 'has worked' requires the past participle. 'Working' is wrong because 'has working' is not a grammatical structure in English; 'working' after 'has' would form a different tense requiring 'been' (has been working). 'Works' is wrong because it is the third-person singular simple present, which does not form a valid tense when placed after 'has'.",category:"Grammar"},
  {id:"p5e13",question:"We are looking for _____ who has experience in software development.",options:["A) everyone","B) someone","C) anyone","D) no one"],answer:"B",explanation:"'Someone' is correct because it refers to an unspecified individual in an affirmative context, which fits a job search where the company seeks a particular type of person. 'Everyone' is wrong because it refers to all people collectively, implying the company is looking for every person, not a single candidate. 'Anyone' is wrong because it is used in questions, negative sentences, or conditional clauses, not in straightforward affirmative statements about seeking a candidate. 'No one' is wrong because it carries a negative meaning, implying nobody is being sought, which contradicts the purpose of the sentence.",category:"Vocabulary"},
  {id:"p5e14",question:"The invoice should be paid _____ 30 days of receipt.",options:["A) within","B) among","C) between","D) through"],answer:"A",explanation:"'Within 30 days' is correct because 'within' means no later than the end of a specified period, indicating a payment deadline measured from a starting point. 'Among' is wrong because it describes relationships or distribution within a group of three or more things, not a time limit. 'Between' is wrong because it refers to a span connecting two defined points, and requires two endpoints (between X and Y), not a single duration from receipt. 'Through' is wrong because it indicates passing from one side to another or a continuous duration, not a deadline expressed as a maximum number of days.",category:"Preposition"},
  {id:"p5e15",question:"The sales figures for this quarter are _____ than last year.",options:["A) high","B) highest","C) higher","D) highly"],answer:"C",explanation:"'Higher' is correct because the sentence compares two things — this quarter and last year — requiring the comparative form of the adjective, which is 'higher'. 'High' is wrong because it is the base form of the adjective, which cannot express a comparison between two items without the comparative suffix or 'more'. 'Highest' is wrong because it is the superlative form, used when something ranks first among three or more items, not when comparing only two. 'Highly' is wrong because it is an adverb typically modifying adjectives or other adverbs (highly skilled), not the main predicate adjective in a comparative structure.",category:"Grammar"},
  {id:"p5e16",question:"Our office will be _____ on national holidays.",options:["A) closed","B) close","C) closing","D) closes"],answer:"A",explanation:"'Closed' is correct because 'be closed' uses the past participle as an adjective to describe the state of the office, and this is the standard way to express that a place is not open. 'Close' is wrong because it is the base verb or adjective meaning near, and after 'will be' the sentence requires a past participle to form the passive or a participial adjective. 'Closing' is wrong because 'will be closing' would form the future continuous, implying the process of closing rather than the state of being closed on holidays. 'Closes' is wrong because it is the third-person singular present simple, which cannot follow the auxiliary 'will be'.",category:"Grammar"},
  {id:"p5e17",question:"The manager asked the staff to _____ their progress reports every Friday.",options:["A) submit","B) submits","C) submitted","D) submission"],answer:"A",explanation:"'Submit' is correct because after the structure 'ask + object + to', the infinitive base form is required, giving 'asked the staff to submit'. 'Submits' is wrong because it is the third-person singular present simple and cannot follow the infinitive marker 'to'. 'Submitted' is wrong because it is the past tense or past participle form, neither of which can follow 'to' in a to-infinitive construction. 'Submission' is wrong because it is a noun, and the structure 'ask + object + to' must be followed by a verb, not a noun.",category:"Grammar"},
  {id:"p5e18",question:"Please _____ free to contact us if you have any questions.",options:["A) feel","B) be","C) make","D) take"],answer:"A",explanation:"'Feel free to' is correct because it is a fixed idiomatic phrase meaning 'do not hesitate to' or 'you are welcome to', and the full expression is 'please feel free to contact us'. 'Be' is wrong because 'be free to' is grammatically possible but is not the established idiomatic expression used in polite invitations and business correspondence. 'Make' is wrong because 'make free to' is not a recognized English expression. 'Take' is wrong because 'take free to' does not exist as a phrase in standard English.",category:"Vocabulary"},
  {id:"p5e19",question:"The training program is _____ for all new hires.",options:["A) mandated","B) mandatory","C) mandate","D) mandating"],answer:"B",explanation:"'Mandatory' is correct because it is an adjective meaning required or compulsory, and after the linking verb 'is' an adjective is needed to describe the training program. 'Mandated' is wrong because it is a past participle that would require a passive verb phrase ('is mandated'), changing the meaning to the program being ordered by someone rather than simply being a required attribute of the program. 'Mandate' is wrong because it is a noun or base verb, neither of which can serve as a predicate adjective after 'is'. 'Mandating' is wrong because it is a present participle functioning as a verb or gerund, not an adjective, and 'is mandating' would imply the program is currently issuing a mandate rather than being required.",category:"Vocabulary"},
  {id:"p5e20",question:"The CEO will _____ the keynote speech at the annual conference.",options:["A) deliver","B) delivery","C) delivered","D) delivering"],answer:"A",explanation:"'Deliver' is correct because after the modal 'will', the base form of the verb is required, and 'deliver a speech' is the standard collocation. 'Delivery' is wrong because it is a noun and cannot follow a modal verb in a verb phrase. 'Delivered' is wrong because it is the past tense or past participle, which cannot directly follow the modal 'will'. 'Delivering' is wrong because the present participle cannot follow a modal verb without the auxiliary 'be' (e.g., 'will be delivering').",category:"Vocabulary"},
  {id:"p5e21",question:"The meeting has been _____ until next Thursday.",options:["A) postpone","B) postponed","C) postponing","D) postponement"],answer:"B",explanation:"'Postponed' is correct because the present perfect passive structure 'has been + past participle' requires the past participle form, giving 'has been postponed'. 'Postpone' is wrong because the base form cannot follow 'has been' in the passive; the past participle 'postponed' is required. 'Postponing' is wrong because 'has been postponing' would form the present perfect continuous active, whereas the sentence describes the meeting as receiving the action (passive). 'Postponement' is wrong because it is a noun and cannot fill the past-participle slot in a passive verb phrase.",category:"Grammar"},
  {id:"p5e22",question:"She has _____ with this company for over fifteen years.",options:["A) work","B) worked","C) working","D) works"],answer:"B",explanation:"'Worked' is correct because the present perfect 'has worked' is required to describe an action or state that began in the past and continues to the present, with the duration 'for over fifteen years'. 'Work' is wrong because the base form cannot follow the auxiliary 'has' to form the present perfect; the past participle 'worked' is required. 'Working' is wrong because 'has working' is not grammatical; the present perfect continuous would need 'has been working'. 'Works' is wrong because the third-person singular present simple cannot follow the auxiliary 'has' in a perfect tense construction.",category:"Grammar"},
  {id:"p5e23",question:"The conference room is _____ until 4 PM today.",options:["A) reserve","B) reserved","C) reserving","D) reservation"],answer:"B",explanation:"'Reserved' is correct because 'is reserved' uses the past participle as an adjective (or passive) to describe the current state of the conference room, meaning it has been booked. 'Reserve' is wrong because the base verb cannot follow the linking verb 'is' to describe a state; the passive or adjectival past participle form is required. 'Reserving' is wrong because 'is reserving' would form the present continuous active, implying the room itself is making a reservation, which is illogical. 'Reservation' is wrong because it is a noun and cannot follow 'is' as a predicate describing the room's state.",category:"Grammar"},
  {id:"p5e24",question:"All visitors must _____ their name at the front desk.",options:["A) registers","B) registering","C) register","D) registered"],answer:"C",explanation:"'Register' is correct because after the modal verb 'must', the base form of the main verb is always required. 'Registers' is wrong because it is the third-person singular present form, which cannot follow a modal verb. 'Registering' is wrong because the present participle cannot directly follow a modal; it would need an auxiliary 'be' (e.g., 'must be registering'). 'Registered' is wrong because the past participle cannot follow a modal in an active sentence; it would need 'be' to form the passive (e.g., 'must be registered').",category:"Grammar"},
  {id:"p5e25",question:"The product _____ available in stores next month.",options:["A) become","B) will become","C) became","D) becoming"],answer:"B",explanation:"'Will become' is correct because the future time marker 'next month' signals that the event has not happened yet, and the future simple 'will + base verb' is used for scheduled future events. 'Become' is wrong because the base form alone cannot serve as the finite verb of the sentence without a modal or auxiliary for a future meaning. 'Became' is wrong because it is the simple past, which contradicts the future time marker 'next month'. 'Becoming' is wrong because the present participle requires an auxiliary verb (e.g., 'is becoming') and does not express a future scheduled event.",category:"Grammar"},
  {id:"p5e26",question:"Could you please _____ me a copy of the agenda?",options:["A) send","B) sends","C) sent","D) sending"],answer:"A",explanation:"'Send' is correct because after the modal 'could', the base form of the main verb is always required, making 'could you please send' the grammatically correct polite request. 'Sends' is wrong because the third-person singular present form cannot follow a modal verb. 'Sent' is wrong because the past tense or past participle cannot follow a modal in an active sentence without 'have' (e.g., 'could have sent'). 'Sending' is wrong because the present participle cannot directly follow a modal; it would need 'be' to form the continuous (e.g., 'could be sending').",category:"Grammar"},
  {id:"p5e27",question:"The director _____ a brief statement to the press yesterday.",options:["A) makes","B) making","C) made","D) make"],answer:"C",explanation:"'Made' is correct because the past time marker 'yesterday' signals a completed action, requiring the simple past tense, and 'make a statement' is the standard collocation. 'Makes' is wrong because it is the third-person singular present simple, which contradicts the past time marker 'yesterday'. 'Making' is wrong because the present participle requires an auxiliary verb and does not express a completed simple past action. 'Make' is wrong because the base form cannot serve as the finite past-tense verb of a sentence.",category:"Grammar"},
  {id:"p5e28",question:"Sales have _____ significantly since we launched the new product.",options:["A) increase","B) increased","C) increasing","D) increases"],answer:"B",explanation:"'Increased' is correct because the present perfect 'have increased' is used with 'since' to describe a change that began at a past point and continues to or is relevant in the present. 'Increase' is wrong because the base form cannot follow the auxiliary 'have' to form the present perfect; the past participle 'increased' is required. 'Increasing' is wrong because 'have increasing' is not grammatical; the present perfect continuous would need 'have been increasing'. 'Increases' is wrong because the third-person singular present form cannot follow the auxiliary 'have' in a perfect tense.",category:"Grammar"},
  {id:"p5e29",question:"If customers _____ any problems, they should call the hotline.",options:["A) experience","B) experienced","C) will experience","D) experiencing"],answer:"A",explanation:"'Experience' is correct because in a first conditional sentence, the 'if' clause requires the present simple tense to describe a real and possible future condition. 'Experienced' is wrong because the simple past in an 'if' clause forms the second conditional, which describes unreal or hypothetical situations, not practical instructions for customers. 'Will experience' is wrong because the future tense is not used in the 'if' clause of a conditional sentence in standard English grammar. 'Experiencing' is wrong because the present participle cannot serve as the finite verb of the 'if' clause without an auxiliary verb.",category:"Grammar"},
  {id:"p5e30",question:"The annual report _____ reviewed by the auditors at this moment.",options:["A) is being","B) is","C) was","D) will"],answer:"A",explanation:"'Is being' is correct because the time expression 'at this moment' signals an action in progress right now, requiring the present continuous passive 'is being + past participle' (is being reviewed). 'Is' is wrong because 'is reviewed' would form the simple present passive, which describes a habitual action, not something happening right now. 'Was' is wrong because it is the past tense, which contradicts the current time expression 'at this moment'. 'Will' is wrong because it is a future modal and would require a following base verb (will be reviewed) to form a complete passive structure, and 'at this moment' indicates present, not future.",category:"Grammar"},
  {id:"p5e31",question:"She arrived _____ the airport two hours before her flight.",options:["A) in","B) on","C) at","D) to"],answer:"C",explanation:"'At' is correct because 'arrive at' is used with specific locations and destinations such as airports, stations, and buildings. 'In' is wrong because 'arrive in' is used with larger geographical areas such as cities and countries, not specific facilities like airports. 'On' is wrong because 'on' does not collocate with 'arrive' to indicate a destination; it is used for surfaces and transport vehicles. 'To' is wrong because 'arrive to' is not standard in English; the correct prepositions after 'arrive' are 'at' (specific places) or 'in' (large areas).",category:"Preposition"},
  {id:"p5e32",question:"The seminar will take place _____ Monday morning.",options:["A) in","B) on","C) at","D) by"],answer:"B",explanation:"'On' is correct because the preposition 'on' is used before specific days of the week and dates, such as 'on Monday'. 'In' is wrong because 'in' is used with months, years, seasons, and parts of the day when no specific day is named (e.g., 'in the morning'), but not with named days. 'At' is wrong because 'at' is used with specific clock times (at 9 AM) and certain fixed expressions (at night), not with named days of the week. 'By' is wrong because 'by' indicates a deadline and does not express when an event will take place.",category:"Preposition"},
  {id:"p5e33",question:"The office is open _____ 9 AM _____ 6 PM on weekdays.",options:["A) from / to","B) since / until","C) between / to","D) at / on"],answer:"A",explanation:"'From / to' is correct because 'from...to...' is the standard structure to express the start and end points of a time range, as in 'open from 9 AM to 6 PM'. 'Since / until' is wrong because 'since' marks the starting point of a state continuing into the present (not a daily schedule), and while 'until' can work for the endpoint, the pair 'since/until' implies a continuous ongoing state rather than a recurring daily schedule. 'Between / to' is wrong because 'between' requires 'and' as its partner preposition (between 9 AM and 6 PM), not 'to'. 'At / on' is wrong because neither 'at' nor 'on' is used to express the beginning of a time range; 'at' marks a point in time and 'on' marks a day.",category:"Preposition"},
  {id:"p5e34",question:"The company was founded _____ 1998.",options:["A) on","B) at","C) in","D) by"],answer:"C",explanation:"'In' is correct because the preposition 'in' is used with years and other longer time periods such as months and seasons. 'On' is wrong because 'on' is used with specific dates and days of the week (on January 1st, on Monday), not with years alone. 'At' is wrong because 'at' is used with specific times of day and certain fixed expressions, not with years. 'By' is wrong because 'by' indicates a deadline or the agent in a passive sentence, not the time period during which something was founded.",category:"Preposition"},
  {id:"p5e35",question:"The report will be ready _____ Friday.",options:["A) until","B) since","C) during","D) by"],answer:"D",explanation:"'By Friday' is correct because 'by' marks a deadline, meaning the report will be ready no later than Friday. 'Until' is wrong because 'until' describes a continuous action or state that lasts up to a point (e.g., 'wait until Friday'), not a deadline for a one-time completion. 'Since' is wrong because 'since' marks the starting point of an action or state that continues into the present, which does not apply to a future deadline. 'During' is wrong because 'during' describes an activity that occurs within a period (e.g., 'during the meeting'), not a specific deadline point.",category:"Preposition"},
  {id:"p5e36",question:"The CEO is traveling _____ business this week.",options:["A) for","B) on","C) in","D) at"],answer:"B",explanation:"'On business' is correct because it is a fixed idiomatic phrase meaning traveling for work-related purposes, and 'on' is the required preposition in this expression. 'For' is wrong because while 'for business' might seem logical (implying purpose), the established fixed phrase used in English is 'on business', not 'for business'. 'In' is wrong because 'in business' means being engaged in commerce as a profession, not traveling for work purposes. 'At' is wrong because 'at business' is not a recognized expression in English.",category:"Preposition"},
  {id:"p5e37",question:"Please respond _____ this invitation by September 15th.",options:["A) for","B) with","C) to","D) at"],answer:"C",explanation:"'Respond to' is correct because the verb 'respond' always takes the preposition 'to' to indicate what is being replied to, making 'respond to this invitation' the correct collocation. 'For' is wrong because 'respond for' is not a standard English construction; 'for' indicates purpose or benefit, not the recipient of a response. 'With' is wrong because 'respond with' would mean to respond using something (respond with a letter), but here the object is what is being responded to, not the means. 'At' is wrong because 'respond at' is not a recognized verb-preposition collocation in English.",category:"Preposition"},
  {id:"p5e38",question:"The package was delivered _____ mistake to the wrong office.",options:["A) in","B) by","C) on","D) with"],answer:"B",explanation:"'By mistake' is correct because it is a fixed idiomatic expression meaning something was done accidentally or in error, and 'by' is the required preposition. 'In' is wrong because 'in mistake' is not a recognized English expression; the correct phrase is always 'by mistake'. 'On' is wrong because 'on mistake' does not exist as a phrase; 'on' is not used with 'mistake' in standard English idioms. 'With' is wrong because 'with mistake' is not an established expression; 'with' indicates accompaniment or means, not accidental error.",category:"Preposition"},
  {id:"p5e39",question:"He will be _____ leave from Monday to Wednesday.",options:["A) on","B) in","C) at","D) for"],answer:"A",explanation:"'On leave' is correct because it is the fixed expression meaning officially absent from work with authorization, and 'on' is the required preposition in this phrase. 'In' is wrong because 'in leave' is not a recognized English expression; the standard phrase is always 'on leave'. 'At' is wrong because 'at leave' does not exist as a fixed phrase in English. 'For' is wrong because 'for leave' would express purpose (applying for leave) rather than describing the state of being absent on approved leave.",category:"Preposition"},
  {id:"p5e40",question:"The new branch is located _____ the corner of Main Street.",options:["A) in","B) at","C) on","D) by"],answer:"C",explanation:"'On the corner' is correct because English uses the preposition 'on' when referring to street corners, as in 'on the corner of Main Street'. 'In' is wrong because 'in the corner' typically refers to an interior space (e.g., a corner inside a room), not a street corner. 'At' is wrong because 'at the corner' refers to the general vicinity or intersection point, whereas the sentence describes the branch's specific location, for which 'on the corner' is the standard idiomatic expression. 'By' is wrong because 'by the corner' means near or beside the corner, not located at the exact corner position.",category:"Preposition"},
  {id:"p5e41",question:"This is _____ most efficient machine we have ever produced.",options:["A) a","B) an","C) the","D) —"],answer:"C",explanation:"'The' is correct because superlative structures (most efficient) always require the definite article 'the', as the superlative singles out one specific item from a group. 'A' is wrong because the indefinite article 'a' introduces a non-specific item and cannot be used with superlatives. 'An' is wrong because 'an' is also an indefinite article used before vowel sounds, and indefinite articles are incompatible with superlative adjectives. No article is wrong because the superlative form grammatically requires 'the' and cannot stand without it.",category:"Article"},
  {id:"p5e42",question:"She submitted _____ application for the managerial position.",options:["A) a","B) an","C) the","D) —"],answer:"B",explanation:"'An' is correct because 'application' begins with the vowel sound /æ/, and the indefinite article 'an' is required before any word starting with a vowel sound. 'A' is wrong because 'a' is used before words that begin with a consonant sound, and 'application' starts with a vowel sound. 'The' is wrong because the definite article 'the' is used for a specific, previously identified application, whereas this sentence introduces the application for the first time. No article is wrong because 'application' is a countable noun in the singular and requires an article when used non-specifically.",category:"Article"},
  {id:"p5e43",question:"We need _____ accountant to review the quarterly figures.",options:["A) a","B) an","C) the","D) —"],answer:"B",explanation:"'An' is correct because 'accountant' begins with a vowel sound /æ/, requiring the indefinite article 'an' before it. 'A' is wrong because 'a' is used before words beginning with a consonant sound, and 'accountant' starts with a vowel sound. 'The' is wrong because 'the' would imply a specific, already-identified accountant, whereas the sentence is looking for any qualified accountant. No article is wrong because 'accountant' is a singular countable noun used non-specifically, which requires an indefinite article.",category:"Article"},
  {id:"p5e44",question:"Please check _____ schedule before confirming the meeting.",options:["A) a","B) an","C) the","D) —"],answer:"C",explanation:"'The' is correct because it refers to a specific schedule that is already known to both the speaker and the listener, making the definite article appropriate. 'A' is wrong because 'a' introduces an unspecified item for the first time, whereas the context implies a particular, shared schedule both parties are aware of. 'An' is wrong because 'schedule' begins with the consonant sound /sk/, so even if an indefinite article were appropriate, 'an' would be incorrect here. No article is wrong because 'schedule' is a singular countable noun in this context and requires an article.",category:"Article"},
  {id:"p5e45",question:"_____ customer service is essential for business success.",options:["A) A","B) An","C) The","D) —"],answer:"D",explanation:"No article is correct because 'customer service' is used here as an uncountable abstract noun in a general statement about a concept, and English does not use articles before uncountable nouns in general statements. 'A' is wrong because 'a' is used with singular countable nouns, and 'customer service' as an abstract concept is uncountable. 'An' is wrong for the same reason as 'a'; 'customer service' is uncountable and cannot take an indefinite article. 'The' is wrong because 'the' would specify a particular customer service (e.g., the customer service at a specific company), whereas this sentence makes a general claim about the concept.",category:"Article"},
  {id:"p5e46",question:"He received _____ unexpected bonus at the end of the year.",options:["A) a","B) an","C) the","D) —"],answer:"B",explanation:"'An' is correct because 'unexpected' begins with the vowel sound /ʌ/, and the indefinite article 'an' is required before any word starting with a vowel sound; the article attaches to the adjective, not the noun. 'A' is wrong because 'a' is used before consonant sounds, and 'unexpected' begins with the vowel sound /ʌ/. 'The' is wrong because 'the' would imply a specific, previously known bonus, whereas the context suggests it was surprising and unspecified. No article is wrong because 'bonus' is a singular countable noun and requires an article when used non-specifically.",category:"Article"},
  {id:"p5e47",question:"Please sign _____ form before leaving the building.",options:["A) a","B) an","C) the","D) —"],answer:"C",explanation:"'The' is correct because the context implies a specific form that both parties know about (a standard exit form at a building), making the definite article appropriate. 'A' is wrong because 'a' would suggest any unspecified form, whereas the instruction refers to a particular known form. 'An' is wrong because 'form' begins with the consonant sound /f/, so even if an indefinite article were correct, 'an' would not be used here. No article is wrong because 'form' is a singular countable noun in a context where a specific, identifiable form is meant.",category:"Article"},
  {id:"p5e48",question:"She made _____ important contribution to the project.",options:["A) a","B) an","C) the","D) —"],answer:"B",explanation:"'An' is correct because 'important' begins with the vowel sound /ɪ/, and the indefinite article must be 'an' before any word starting with a vowel sound; the article attaches to the first word of the noun phrase, which is the adjective. 'A' is wrong because 'a' is used before consonant sounds, and 'important' begins with the vowel sound /ɪ/. 'The' is wrong because 'the' would suggest a specific contribution already identified in context, whereas this sentence introduces the contribution for the first time. No article is wrong because 'contribution' is a singular countable noun requiring an article when introduced non-specifically.",category:"Article"},
  {id:"p5e49",question:"We are looking for _____ experienced engineer to join our team.",options:["A) a","B) an","C) the","D) —"],answer:"B",explanation:"'An' is correct because 'experienced' begins with the vowel sound /ɪ/, requiring the indefinite article 'an' before it, as the article governs the sound of the first word in the noun phrase. 'A' is wrong because 'a' precedes consonant sounds, and 'experienced' starts with the vowel sound /ɪ/. 'The' is wrong because 'the' would refer to a specific, already-identified engineer, whereas the company is searching for any qualified individual. No article is wrong because 'engineer' is a singular countable noun in a non-specific context and requires an indefinite article.",category:"Article"},
  {id:"p5e50",question:"_____ new office building will open next spring.",options:["A) A","B) An","C) The","D) —"],answer:"C",explanation:"'The' is correct because the sentence refers to a specific building that has already been established in the context, so the definite article is required to signal a unique, known referent. 'A' is wrong because the indefinite article 'a' introduces an unspecified item not previously mentioned, which contradicts the specific building being discussed. 'An' is wrong because 'new' begins with the consonant sound /n/, so 'an' would be phonetically incorrect even if an indefinite article were appropriate. No article is wrong because 'office building' is a singular countable noun and requires an article.",category:"Article"},
  {id:"p5e51",question:"You _____ wear a hard hat in the construction zone at all times.",options:["A) should","B) must","C) might","D) could"],answer:"B",explanation:"'Must' is correct because it expresses strong obligation and is the appropriate modal for mandatory safety rules that allow no exceptions. 'Should' is wrong because 'should' expresses a recommendation or advisability, implying there is some flexibility, which is not appropriate for a strict safety requirement. 'Might' is wrong because 'might' expresses a weak possibility (something that may or may not happen), not an obligation or requirement. 'Could' is wrong because 'could' expresses ability or a polite possibility, not a mandatory obligation imposed by safety regulations.",category:"Modal"},
  {id:"p5e52",question:"Employees _____ take a 30-minute lunch break each day.",options:["A) should","B) might","C) may","D) can"],answer:"D",explanation:"'Can' is correct because it expresses permission — employees are allowed to take a lunch break — which fits the workplace policy context of granting an entitlement. 'Should' is wrong because 'should' implies a recommendation or moral obligation, suggesting employees are expected to take a break rather than being permitted to. 'Might' is wrong because 'might' expresses a weak possibility, not permission or an entitlement granted by policy. 'May' is wrong in this specific context because 'may' expresses formal permission granted by authority (as in a rule or policy decision), whereas 'can' describes an established entitlement or practical ability that employees already have.",category:"Modal"},
  {id:"p5e53",question:"You _____ bring your laptop to the meeting if you need to.",options:["A) must","B) should","C) can","D) would"],answer:"C",explanation:"'Can' is correct because it expresses permission or the option to do something, making it appropriate for an optional offer to bring a laptop if needed. 'Must' is wrong because 'must' expresses a strong obligation, implying bringing the laptop is mandatory, which contradicts the conditional 'if you need to'. 'Should' is wrong because 'should' expresses advice or recommendation with a sense of expectation, which is stronger than the optional invitation intended here. 'Would' is wrong because 'would' is typically used for conditional or hypothetical statements, polite requests, or habitual past actions, not for granting permission.",category:"Modal"},
  {id:"p5e54",question:"We _____ reach the sales target if we focus on key accounts.",options:["A) can","B) must","C) ought","D) shall"],answer:"A",explanation:"'Can' is correct because it expresses the possibility or ability to achieve something under a certain condition, fitting the idea that focusing on key accounts makes the target achievable. 'Must' is wrong because 'must' expresses obligation or logical certainty, not a conditional possibility dependent on a chosen strategy. 'Ought' is wrong because 'ought' (ought to) expresses moral duty or advisability, not the conditional ability or possibility described here. 'Shall' is wrong because 'shall' in modern business English is used for formal proposals or offers (shall we?), not to express conditional possibility.",category:"Modal"},
  {id:"p5e55",question:"The meeting _____ start without the client's confirmation.",options:["A) shouldn't","B) mustn't","C) mightn't","D) couldn't"],answer:"A",explanation:"'Shouldn't' is correct because it expresses strong advice against an action, indicating it would be inadvisable or inappropriate to start the meeting without confirmation, while leaving room for judgment. 'Mustn't' is wrong because 'mustn't' expresses a strict prohibition with no exceptions, which is stronger than what the context implies — the sentence advises against starting, not absolutely forbids it. 'Mightn't' is wrong because 'mightn't' (might not) expresses a low probability that something will happen, making it a statement about uncertainty rather than advice or guidance about what should be done. 'Couldn't' is wrong because 'couldn't' expresses inability, suggesting the meeting is incapable of starting, not that it would be wrong to do so.",category:"Modal"},
  {id:"p5e56",question:"_____ you please forward this email to the sales team?",options:["A) Would","B) Should","C) Must","D) Shall"],answer:"A",explanation:"'Would' is correct because 'Would you please...' is a standard polite request formula in English, making it the appropriate choice for a courteous professional request. 'Should' is wrong because 'Should you please...' is not a recognized polite request structure; 'should' expresses obligation or advice, not a courteous invitation to act. 'Must' is wrong because 'Must you please...' is grammatically awkward and sounds like a demand rather than a polite request. 'Shall' is wrong because 'Shall you...' is not a standard English construction for requests; 'shall' with second person is archaic and not used for polite modern requests.",category:"Modal"},
  {id:"p5e57",question:"She _____ speak Japanese, which is very helpful for our Tokyo clients.",options:["A) must","B) can","C) should","D) would"],answer:"B",explanation:"'Can' is correct because it expresses ability — she has the skill to speak Japanese — which is the meaning conveyed by the sentence. 'Must' is wrong because 'must' expresses obligation or logical deduction (she must speak Japanese = it is logical she does), which changes the meaning to an inference rather than a statement of established ability. 'Should' is wrong because 'should' expresses what is advisable or expected, implying she ought to speak Japanese rather than stating that she actually does. 'Would' is wrong because 'would' in this context would suggest a conditional or hypothetical ability, not a real, confirmed skill.",category:"Modal"},
  {id:"p5e58",question:"Staff _____ use the emergency exit during a real fire only.",options:["A) should","B) may","C) would","D) could"],answer:"A",explanation:"'Should' is correct because it expresses a strong recommendation or guidance for the appropriate use of the emergency exit, fitting an official workplace instruction. 'May' is wrong because 'may' simply grants permission without the sense of guidance or instruction that a safety protocol conveys. 'Would' is wrong because 'would' typically describes habitual past actions or conditional situations, not current official guidelines. 'Could' is wrong because 'could' expresses past ability or possibility, not a current authoritative recommendation on how to use the emergency exit.",category:"Modal"},
  {id:"p5e59",question:"The delivery _____ arrive late due to the traffic.",options:["A) would","B) should","C) might","D) must"],answer:"C",explanation:"'Might' is correct because it expresses a weak or uncertain possibility — the delivery may or may not be late — which fits the context of traffic-related uncertainty. 'Would' is wrong because 'would' in this context implies a conditional outcome or a near-certainty based on a condition, which is stronger than the uncertain possibility the sentence intends. 'Should' is wrong because 'should' expresses expectation or advisability, implying the delivery is expected to arrive late, which conveys more certainty than intended. 'Must' is wrong because 'must' expresses either a strong obligation or a logical deduction with high certainty, neither of which fits the uncertain possibility of traffic delays.",category:"Modal"},
  {id:"p5e60",question:"All attendees _____ register online before the event.",options:["A) should","B) must","C) might","D) could"],answer:"B",explanation:"'Must' is correct because it expresses a mandatory requirement with no exceptions — all attendees are obligated to register online before the event. 'Should' is wrong because 'should' expresses a recommendation or advisability, implying registration is strongly suggested but not strictly required. 'Might' is wrong because 'might' expresses a weak possibility, not an obligation or mandatory rule. 'Could' is wrong because 'could' expresses ability or a polite possibility, not a non-negotiable requirement.",category:"Modal"},
  {id:"p5e61",question:"The _____ of the new branch was a major achievement.",options:["A) open","B) opening","C) opened","D) openly"],answer:"B",explanation:"'Opening' is correct because after the definite article 'The', a noun is required as the subject of the sentence, and 'opening' functions as a gerund/noun meaning the act or event of officially starting something. 'Open' is wrong because in this position after 'The', 'open' would function as an adjective or base verb, neither of which can serve as the noun subject of the sentence. 'Opened' is wrong because it is a past tense verb or past participle, which cannot serve as the subject noun of a sentence after the definite article. 'Openly' is wrong because it is an adverb meaning frankly or without concealment, which cannot function as a noun subject.",category:"Word Form"},
  {id:"p5e62",question:"He gave a very _____ speech at the retirement party.",options:["A) move","B) moved","C) moving","D) movement"],answer:"C",explanation:"'Moving' is correct because it functions as a participial adjective meaning emotionally touching or stirring, modifying the noun 'speech'. 'Move' is wrong because it is the base verb and cannot directly modify a noun in the adjective position. 'Moved' is wrong because 'moved' as an adjective describes the person who feels emotion (he was moved), not the thing that causes the emotion (a moving speech). 'Movement' is wrong because it is a noun meaning a physical motion or a social cause, and nouns cannot modify other nouns in this adjectival position.",category:"Word Form"},
  {id:"p5e63",question:"Please handle all customer requests _____ and courteously.",options:["A) prompt","B) promptly","C) promptness","D) prompted"],answer:"B",explanation:"'Promptly' is correct because an adverb is needed to modify the verb 'handle', and 'promptly' means in a quick and timely manner. 'Prompt' is wrong because it is an adjective and cannot modify a verb; adjectives modify nouns, not actions. 'Promptness' is wrong because it is a noun meaning the quality of being prompt, and a noun cannot serve as an adverb to modify 'handle'. 'Prompted' is wrong because it is the past tense or past participle of the verb 'prompt', which cannot function as an adverb modifying another verb.",category:"Word Form"},
  {id:"p5e64",question:"The team showed great _____ in completing the project ahead of schedule.",options:["A) efficient","B) efficiently","C) efficiency","D) efficiencies"],answer:"C",explanation:"'Efficiency' is correct because after the adjective 'great', a noun is required as the object of 'showed', and 'efficiency' is the uncountable noun form meaning the quality of working effectively without waste. 'Efficient' is wrong because it is an adjective, and adjectives cannot serve as the object of a verb or follow 'great' in this noun phrase structure. 'Efficiently' is wrong because it is an adverb that modifies verbs or adjectives, not a noun that can follow 'great' as the object of 'showed'. 'Efficiencies' is wrong because 'efficiency' is typically used as an uncountable noun in this context, and the plural form is uncommon and unnatural here.",category:"Word Form"},
  {id:"p5e65",question:"We are committed to providing _____ customer service.",options:["A) excellence","B) excellent","C) excel","D) excellently"],answer:"B",explanation:"'Excellent' is correct because an adjective is needed to modify the noun 'customer service', and 'excellent' means of very high quality. 'Excellence' is wrong because it is a noun meaning the state of being excellent, and a noun cannot directly modify another noun in this attributive adjective position. 'Excel' is wrong because it is a verb meaning to be very good at something, and a verb cannot modify a noun. 'Excellently' is wrong because it is an adverb that modifies verbs or adjectives, not a noun such as 'customer service'.",category:"Word Form"},
  {id:"p5e66",question:"The new regulation requires _____ reporting of safety incidents.",options:["A) immediate","B) immediately","C) immediacy","D) immediateness"],answer:"A",explanation:"'Immediate' is correct because an adjective is needed to modify the noun 'reporting', and 'immediate' means done without delay. 'Immediately' is wrong because it is an adverb that modifies verbs or adjectives, not a noun; it cannot directly precede and modify 'reporting' in this noun phrase. 'Immediacy' is wrong because it is a noun meaning the quality of being immediate, and a noun cannot modify another noun in this attributive position. 'Immediateness' is wrong because it is a non-standard or rarely used noun form, and even if accepted, it cannot serve as an adjective to modify 'reporting'.",category:"Word Form"},
  {id:"p5e67",question:"The proposal was written very _____ and clearly.",options:["A) concise","B) concisely","C) conciseness","D) concised"],answer:"B",explanation:"'Concisely' is correct because an adverb is needed to modify the past participle 'written', describing how the proposal was written, and 'concisely' means in a brief and clear manner. 'Concise' is wrong because it is an adjective that modifies nouns, not verbs or past participles; it cannot describe how something was written. 'Conciseness' is wrong because it is a noun meaning the quality of being concise, and a noun cannot modify a verb or past participle. 'Concised' is wrong because 'concised' is not a standard English word; 'concise' has no past participle form as it is not used as a verb.",category:"Word Form"},
  {id:"p5e68",question:"The _____ of the software project was completed on time.",options:["A) develop","B) developer","C) development","D) developed"],answer:"C",explanation:"'Development' is correct because after the definite article 'The', a noun is needed as the subject of the sentence, and 'development' is the noun form meaning the process of creating or building something. 'Develop' is wrong because it is a base verb, and verbs cannot directly follow the definite article 'The' to serve as the subject of a sentence. 'Developer' is wrong because 'developer' refers to a person who develops, and the sentence is about the process (development) being completed, not a person. 'Developed' is wrong because it is a past tense verb or past participle, neither of which can follow 'The' as a noun subject.",category:"Word Form"},
  {id:"p5e69",question:"She is highly _____ in her field and well respected.",options:["A) qualify","B) qualified","C) qualification","D) qualifying"],answer:"B",explanation:"'Qualified' is correct because it functions as a participial adjective after the linking verb 'is', meaning she has the required skills and credentials in her field. 'Qualify' is wrong because it is the base verb form, and the base verb cannot follow a linking verb like 'is' to describe the subject. 'Qualification' is wrong because it is a noun referring to a credential or certificate, and a noun cannot serve as a predicate adjective after 'is' in this structure. 'Qualifying' is wrong because the present participle 'qualifying' after 'is' would form the present continuous tense (she is qualifying), implying she is currently in the process of gaining qualifications.",category:"Word Form"},
  {id:"p5e70",question:"The manager gave _____ feedback on the team's performance.",options:["A) construct","B) constructive","C) construction","D) constructively"],answer:"B",explanation:"'Constructive' is correct because an adjective is needed to modify the noun 'feedback', and 'constructive' means intended to be helpful and improve the situation. 'Construct' is wrong because it is a base verb or noun, neither of which can serve as an adjective to modify 'feedback' in this noun phrase. 'Construction' is wrong because it is a noun referring to the process of building something, and a noun cannot modify another noun in this attributive adjective position. 'Constructively' is wrong because it is an adverb that modifies verbs or adjectives, not a noun such as 'feedback'.",category:"Word Form"},
  {id:"p5e71",question:"We need to _____ the budget before the board meeting.",options:["A) finalize","B) final","C) finally","D) finality"],answer:"A",explanation:"'Finalize' is correct because after the infinitive marker 'to', the base form of a verb is required, and 'finalize' means to complete or put the finishing touches on something. 'Final' is wrong because it is an adjective meaning last or conclusive, and adjectives cannot follow the infinitive marker 'to' as a main verb. 'Finally' is wrong because it is an adverb meaning at last or in conclusion, and adverbs cannot serve as the main verb after 'to'. 'Finality' is wrong because it is a noun meaning the quality of being final or conclusive, and nouns cannot follow the infinitive marker 'to' as a verb.",category:"Word Form"},
  {id:"p5e72",question:"The _____ of the new product line has been very positive.",options:["A) receive","B) receipt","C) reception","D) receiving"],answer:"C",explanation:"'Reception' is correct because in this context it means the way something is received or responded to (public or critical reaction), which is the intended meaning, and it functions as a noun subject after 'The'. 'Receive' is wrong because it is a base verb and cannot serve as the noun subject of the sentence after the definite article. 'Receipt' is wrong because 'receipt' means the act of physically receiving a payment or document, not the overall reaction or response to a product launch. 'Receiving' is wrong because while 'receiving' can function as a gerund, 'reception' is the more precise and standard term for describing public reaction to a new product.",category:"Word Form"},
  {id:"p5e73",question:"Her _____ presentation impressed the entire board of directors.",options:["A) impress","B) impression","C) impressive","D) impressively"],answer:"C",explanation:"'Impressive' is correct because an adjective is needed to modify the noun 'presentation' in the attributive position before the noun. 'Impress' is wrong because it is a base verb, and verbs cannot directly precede and modify a noun in the attributive position. 'Impression' is wrong because it is a noun meaning the effect produced on someone's mind, and a noun cannot modify another noun in this adjective slot. 'Impressively' is wrong because it is an adverb that modifies verbs or adjectives, not a noun such as 'presentation'.",category:"Word Form"},
  {id:"p5e74",question:"The team worked with _____ to meet the tight deadline.",options:["A) dedicate","B) dedicated","C) dedication","D) dedicatedly"],answer:"C",explanation:"'Dedication' is correct because after the preposition 'with', a noun is required, and 'dedication' is the noun form meaning strong commitment and hard work. 'Dedicate' is wrong because it is a base verb, and verbs cannot directly follow a preposition to serve as its object. 'Dedicated' is wrong because it is a past participle or adjective; while adjectives can occasionally follow prepositions in certain constructions, the natural noun form 'dedication' is what is needed here as the object of 'with'. 'Dedicatedly' is wrong because it is an adverb and cannot serve as the noun object of the preposition 'with'.",category:"Word Form"},
  {id:"p5e75",question:"Please keep all patient records _____ at all times.",options:["A) confide","B) confident","C) confidential","D) confidently"],answer:"C",explanation:"'Confidential' is correct because an adjective is needed in the object complement position after 'keep + object', meaning the records must be kept in a private and secret state. 'Confide' is wrong because it is a base verb meaning to share secrets with someone, and a verb cannot serve as an object complement adjective after 'keep'. 'Confident' is wrong because it means feeling sure about one's own abilities or a situation, which describes a person's feeling, not the status of records. 'Confidently' is wrong because it is an adverb that would modify a verb, not an adjective complement describing the required state of the records.",category:"Word Form"},
  {id:"p5e76",question:"The company will _____ a new line of eco-friendly products.",options:["A) introduce","B) introduction","C) introduced","D) introducing"],answer:"A",explanation:"'Introduce' is correct because after the modal 'will', the base form of the main verb is required, and 'introduce a product line' is the standard business collocation meaning to launch something new to the market. 'Introduction' is wrong because it is a noun and cannot follow a modal verb as the main verb of the sentence. 'Introduced' is wrong because the past tense or past participle cannot directly follow the modal 'will'; it would need 'have been' to form the passive perfect. 'Introducing' is wrong because the present participle cannot directly follow a modal; 'will be introducing' would be required for the future continuous.",category:"Vocabulary"},
  {id:"p5e77",question:"We need to _____ a strategy for the upcoming product launch.",options:["A) develop","B) development","C) developer","D) developing"],answer:"A",explanation:"'Develop' is correct because after the infinitive marker 'to', the base verb form is required, and 'develop a strategy' is the standard business collocation meaning to create and build a plan. 'Development' is wrong because it is a noun and cannot follow the infinitive marker 'to' as a main verb. 'Developer' is wrong because it is a noun referring to a person or entity that develops something, not a verb that can follow 'to'. 'Developing' is wrong because the present participle cannot follow the infinitive marker 'to'; the base form 'develop' is required.",category:"Vocabulary"},
  {id:"p5e78",question:"The team will _____ weekly to track the project's progress.",options:["A) meet","B) meeting","C) met","D) meets"],answer:"A",explanation:"'Meet' is correct because after the modal 'will', the base form of the main verb is required, and 'meet weekly' is a natural expression for regularly scheduled group gatherings. 'Meeting' is wrong because the present participle cannot directly follow a modal; 'will be meeting' would be required for the future continuous. 'Met' is wrong because the past tense cannot follow a modal in a standard active sentence; it would require 'have' (will have met) for the future perfect. 'Meets' is wrong because the third-person singular present form cannot follow a modal verb.",category:"Vocabulary"},
  {id:"p5e79",question:"Please _____ the attached document before signing.",options:["A) review","B) reviews","C) reviewed","D) reviewing"],answer:"A",explanation:"'Review' is correct because 'please' followed by the base form creates a polite imperative, and 'review a document' is the standard collocation meaning to read and assess it carefully. 'Reviews' is wrong because the third-person singular present form cannot be used in an imperative; imperatives use the base form. 'Reviewed' is wrong because the past tense or past participle is not used in the imperative; the base form is required. 'Reviewing' is wrong because the present participle cannot form an imperative on its own; it requires an auxiliary verb.",category:"Vocabulary"},
  {id:"p5e80",question:"The HR department will _____ all applicants by phone.",options:["A) contact","B) contacts","C) contacted","D) contacting"],answer:"A",explanation:"'Contact' is correct because after the modal 'will', the base form of the main verb is required, and 'contact applicants' is the natural expression for reaching out to candidates. 'Contacts' is wrong because the third-person singular present form cannot follow a modal verb. 'Contacted' is wrong because the past tense or past participle cannot follow 'will' directly in an active sentence. 'Contacting' is wrong because the present participle cannot directly follow a modal; 'will be contacting' would be required for the future continuous.",category:"Vocabulary"},
  {id:"p5e81",question:"We are pleased to _____ that you have been selected for the position.",options:["A) inform","B) informing","C) informed","D) information"],answer:"A",explanation:"'Inform' is correct because after the structure 'pleased to', the base infinitive form is required, giving the standard business expression 'pleased to inform you'. 'Informing' is wrong because the present participle cannot follow the infinitive marker 'to'; the base form 'inform' is required. 'Informed' is wrong because the past participle cannot follow 'to' as a standard infinitive; it would need 'be' to form the passive (to be informed). 'Information' is wrong because it is a noun and cannot follow the infinitive marker 'to' as a verb.",category:"Vocabulary"},
  {id:"p5e82",question:"The company plans to _____ its operations to Southeast Asia.",options:["A) expand","B) expansion","C) expanding","D) expanded"],answer:"A",explanation:"'Expand' is correct because after the structure 'plans to', the base infinitive form is required, and 'expand operations' is the standard business collocation for growing into new markets. 'Expansion' is wrong because it is a noun and cannot follow the infinitive marker 'to' as a verb. 'Expanding' is wrong because the present participle cannot follow 'to' as an infinitive; the base form is required. 'Expanded' is wrong because the past participle cannot follow 'to' as a standard active infinitive; it would need 'be' to form the passive (to be expanded).",category:"Vocabulary"},
  {id:"p5e83",question:"Could you _____ the meeting for next Wednesday instead?",options:["A) reschedule","B) rescheduling","C) rescheduled","D) reschedules"],answer:"A",explanation:"'Reschedule' is correct because after the modal 'could', the base form of the main verb is required, and 'reschedule a meeting' is the standard phrase for changing a scheduled appointment to a new time. 'Rescheduling' is wrong because the present participle cannot directly follow a modal; 'could be rescheduling' would be needed for the continuous. 'Rescheduled' is wrong because the past participle cannot follow 'could' in an active sentence without the auxiliary 'be' (could be rescheduled) or 'have' (could have rescheduled). 'Reschedules' is wrong because the third-person singular present form cannot follow a modal verb.",category:"Vocabulary"},
  {id:"p5e84",question:"The supervisor will _____ the performance review next week.",options:["A) conduct","B) conducting","C) conducted","D) conducts"],answer:"A",explanation:"'Conduct' is correct because after the modal 'will', the base form of the main verb is required, and 'conduct a performance review' is the standard professional collocation. 'Conducting' is wrong because the present participle cannot directly follow a modal; 'will be conducting' would be required for the future continuous. 'Conducted' is wrong because the past tense or past participle cannot follow 'will' directly in an active sentence. 'Conducts' is wrong because the third-person singular present form cannot follow a modal verb.",category:"Vocabulary"},
  {id:"p5e85",question:"Please _____ your parking permit from the security office.",options:["A) collect","B) collecting","C) collected","D) collects"],answer:"A",explanation:"'Collect' is correct because 'please' followed by the base verb form creates a polite imperative, and 'collect a permit' is the natural expression for picking something up from an office. 'Collecting' is wrong because the present participle cannot form an imperative on its own; it requires an auxiliary verb. 'Collected' is wrong because the past tense or past participle cannot be used in the imperative; the base form is required. 'Collects' is wrong because the third-person singular present form is not used in imperatives; imperatives use the base form without subject or inflection.",category:"Vocabulary"},
  {id:"p5e86",question:"This year's profits are _____ than those of last year.",options:["A) high","B) higher","C) highest","D) highly"],answer:"B",explanation:"'Higher' is correct because the sentence compares two distinct periods — this year and last year — requiring the comparative form of the adjective, formed by adding '-er'. 'High' is wrong because it is the base form of the adjective, which cannot express a comparison without the comparative suffix or 'more'. 'Highest' is wrong because it is the superlative form, used when identifying the top item among three or more, not when comparing two periods. 'Highly' is wrong because it is an adverb typically used to modify adjectives (highly skilled) and cannot serve as a comparative adjective in this sentence.",category:"Comparative"},
  {id:"p5e87",question:"She is the _____ candidate for the senior manager role.",options:["A) strong","B) stronger","C) strongest","D) strongly"],answer:"C",explanation:"'Strongest' is correct because it is the superlative form of 'strong', used to identify the candidate who ranks above all others, and the definite article 'the' before it confirms a superlative is required. 'Strong' is wrong because it is the base adjective form, which makes no comparison and cannot be used with 'the' in a superlative structure. 'Stronger' is wrong because it is the comparative form used for comparing two candidates, but the context ('the') implies she is the best among all candidates. 'Strongly' is wrong because it is an adverb that modifies verbs or adjectives, not the predicate adjective identifying the best candidate.",category:"Comparative"},
  {id:"p5e88",question:"The new model is _____ expensive than the previous version.",options:["A) more","B) most","C) much","D) very"],answer:"A",explanation:"'More' is correct because 'expensive' is a multi-syllable adjective that forms its comparative with 'more' rather than with the suffix '-er', giving 'more expensive than'. 'Most' is wrong because 'most' forms the superlative (most expensive), not the comparative, and the word 'than' following the blank signals a comparative structure. 'Much' is wrong because 'much' alone cannot form the comparative of an adjective; it can intensify a comparative (much more expensive) but cannot replace 'more'. 'Very' is wrong because 'very' is an intensifier that modifies base adjectives, not comparatives, and 'very expensive than' is not grammatically correct.",category:"Comparative"},
  {id:"p5e89",question:"This is by far the _____ project we have handled.",options:["A) complex","B) more complex","C) most complex","D) complexly"],answer:"C",explanation:"'Most complex' is correct because the structure 'the most + adjective' forms the superlative, and the intensifier 'by far' strengthens the superlative claim that this project exceeds all others in complexity. 'Complex' is wrong because the base adjective form without 'most' does not create a superlative, even when preceded by 'the'. 'More complex' is wrong because it is the comparative form used for comparing two items, whereas 'by far the...' signals a superlative comparing against all projects handled. 'Complexly' is wrong because it is an adverb and cannot follow 'the' as a predicate adjective or superlative modifier.",category:"Comparative"},
  {id:"p5e90",question:"The new office is twice as _____ as the old one.",options:["A) large","B) larger","C) largest","D) largely"],answer:"A",explanation:"'Large' is correct because the 'as...as' equality comparison structure requires the base form of the adjective between the two 'as' words, as in 'twice as large as'. 'Larger' is wrong because the comparative form is used with 'than', not within the 'as...as' structure. 'Largest' is wrong because the superlative form is used with 'the' to rank something highest, not within an equality comparison. 'Largely' is wrong because it is an adverb meaning mostly or to a great extent, and adverbs cannot fill the adjective slot in an 'as...as' comparison.",category:"Comparative"},
  {id:"p5e91",question:"Our prices are _____ competitive than those of our rivals.",options:["A) more","B) most","C) very","D) much"],answer:"A",explanation:"'More' is correct because 'competitive' is a multi-syllable adjective that forms its comparative with 'more', and the word 'than' signals that a comparative structure is needed. 'Most' is wrong because 'most' forms the superlative (most competitive), not the comparative, and the presence of 'than' confirms a comparative is required. 'Very' is wrong because 'very' intensifies base adjectives (very competitive) but cannot be used with 'than' to create a comparative. 'Much' is wrong because 'much' alone cannot form the comparative of an adjective; it is used to intensify a comparative already formed (much more competitive).",category:"Comparative"},
  {id:"p5e92",question:"The team finished the project _____ than expected.",options:["A) early","B) earlier","C) earliest","D) too early"],answer:"B",explanation:"'Earlier' is correct because the word 'than' signals a comparison between the actual finish time and what was expected, requiring the comparative adverb form 'earlier'. 'Early' is wrong because it is the base adverb form, which cannot express a comparison with 'than'; the comparative form with '-er' is needed. 'Earliest' is wrong because it is the superlative form, used when something ranks first among three or more, not when comparing two points in time. 'Too early' is wrong because 'too' implies an excessive or undesirable degree, which changes the meaning from a simple comparison to a negative judgment about the timing.",category:"Comparative"},
  {id:"p5e93",question:"Of all the options, this plan is _____ cost-effective.",options:["A) more","B) most","C) the most","D) as most"],answer:"C",explanation:"'The most' is correct because a superlative is needed when comparing one item against all others ('of all the options'), and the superlative requires the definite article 'the' before 'most'. 'More' is wrong because it forms the comparative for comparing two items, but 'of all the options' indicates a comparison among multiple options requiring a superlative. 'Most' is wrong because while 'most' is the superlative word, English superlative constructions require the definite article 'the' before 'most' when modifying an adjective. 'As most' is wrong because 'as most' is not a recognized comparative or superlative structure in English.",category:"Comparative"},
  {id:"p5e94",question:"Please reply as _____ as possible so we can confirm the booking.",options:["A) soon","B) sooner","C) soonest","D) soonly"],answer:"A",explanation:"'As soon as possible' is correct because it is a fixed idiomatic expression (often abbreviated ASAP) meaning at the earliest opportunity, and requires the base adjective/adverb form between the two 'as' words. 'Sooner' is wrong because the comparative form is used with 'than', not within the 'as...as' equality structure. 'Soonest' is wrong because the superlative form is used with 'the' to rank something first, not within an 'as...as' fixed expression. 'Soonly' is wrong because 'soonly' is not a word in English; 'soon' already functions as an adverb and does not take an '-ly' suffix.",category:"Comparative"},
  {id:"p5e95",question:"The _____ the response time, the higher the customer satisfaction.",options:["A) fast","B) faster","C) fastest","D) most fast"],answer:"B",explanation:"'Faster' is correct because the correlative comparison structure 'the + comparative...the + comparative' requires the comparative form of the adjective or adverb in both clauses, as in 'the faster...the higher'. 'Fast' is wrong because the base form cannot be used in the 'the...the...' correlative comparative structure, which always requires comparative forms. 'Fastest' is wrong because the superlative form is used to rank something highest among all options, not in the correlative 'the...the...' structure. 'Most fast' is wrong because 'fast' forms its comparative with '-er' (faster), not with 'most', making 'most fast' non-standard and incorrect.",category:"Comparative"},
  {id:"p5e96",question:"The technician repaired the machine very _____ .",options:["A) quick","B) quickly","C) quickness","D) quicken"],answer:"B",explanation:"'Quickly' is correct because an adverb is needed to modify the verb 'repaired', describing how the action was performed, and 'quickly' is the adverb form meaning in a fast manner. 'Quick' is wrong because it is an adjective that modifies nouns, not a verb; it cannot describe how 'repaired' was done. 'Quickness' is wrong because it is a noun meaning the quality of being fast, and a noun cannot modify a verb to describe the manner of an action. 'Quicken' is wrong because it is a verb meaning to make faster or more lively, not an adverb that can modify another verb.",category:"Word Form"},
  {id:"p5e97",question:"It is _____ to verify all information before submission.",options:["A) importance","B) important","C) importantly","D) import"],answer:"B",explanation:"'Important' is correct because in the structure 'it is + adjective + to-infinitive', an adjective is required after the linking verb 'is' to describe the importance of the action. 'Importance' is wrong because it is a noun, and the pattern 'it is + noun' does not work here; the pattern requires an adjective. 'Importantly' is wrong because it is an adverb used to introduce a key point in discourse (more importantly), not an adjective that can follow 'is' in this structure. 'Import' is wrong because it is a verb or noun related to bringing goods into a country, which is semantically unrelated and grammatically incorrect in this structure.",category:"Word Form"},
  {id:"p5e98",question:"The _____ of the new branch created 50 new jobs.",options:["A) open","B) openly","C) opening","D) opened"],answer:"C",explanation:"'Opening' is correct because after the definite article 'The', a noun is required as the subject of the sentence, and 'opening' functions as a gerund/noun meaning the event or act of officially launching a new location. 'Open' is wrong because in this position after 'The', 'open' functions as an adjective or base verb, neither of which can serve as the noun subject of the sentence. 'Openly' is wrong because it is an adverb meaning in a frank or unconcealed manner, which cannot serve as a noun subject after the definite article. 'Opened' is wrong because it is a past tense verb or past participle, which cannot follow 'The' as the noun subject of a sentence.",category:"Word Form"},
  {id:"p5e99",question:"We are _____ pleased to welcome our new COO.",options:["A) extreme","B) extremely","C) extremeness","D) extremed"],answer:"B",explanation:"'Extremely' is correct because an adverb is needed to modify the adjective 'pleased', intensifying the degree to which the subject is pleased, and 'extremely' is the standard adverb form. 'Extreme' is wrong because it is an adjective that modifies nouns, not other adjectives; it cannot modify 'pleased'. 'Extremeness' is wrong because it is a non-standard noun form meaning the quality of being extreme, and a noun cannot modify an adjective. 'Extremed' is wrong because 'extremed' is not a recognized word in English; 'extreme' does not have a past participle form.",category:"Word Form"},
  {id:"p5e100",question:"The department head made a _____ decision under pressure.",options:["A) wise","B) wisely","C) wisdom","D) wisened"],answer:"A",explanation:"'Wise' is correct because an adjective is needed in the attributive position before the noun 'decision', and 'wise' means showing good judgment and experience. 'Wisely' is wrong because it is an adverb that modifies verbs or other adjectives, not a noun such as 'decision'. 'Wisdom' is wrong because it is a noun meaning the quality of being wise, and a noun cannot modify another noun in the attributive adjective position. 'Wisened' is wrong because it is not a standard English word; 'wisen' is not commonly used as a verb, making 'wisened' non-standard.",category:"Word Form"},
  {id:"p5e101",question:"The HR team is _____ new staff members this month.",options:["A) recruit","B) recruits","C) recruiting","D) recruited"],answer:"C",explanation:"'Recruiting' is correct because the present continuous tense 'is + present participle' is used to describe an activity in progress during the current period, matching the time expression 'this month'. 'Recruit' is wrong because the base form cannot follow the auxiliary 'is' to form the present continuous; the present participle 'recruiting' is required. 'Recruits' is wrong because the third-person singular present simple cannot follow the auxiliary 'is'; it forms simple present, not continuous. 'Recruited' is wrong because the past participle following 'is' would create the passive voice (is recruited), implying the HR team is being recruited, which reverses the meaning.",category:"Grammar"},
  {id:"p5e102",question:"The factory _____ production due to supply chain disruptions.",options:["A) halt","B) halted","C) halting","D) halts"],answer:"B",explanation:"'Halted' is correct because the context describes a completed action in the past (caused by supply chain disruptions), requiring the simple past tense. 'Halt' is wrong because the base form alone cannot serve as the finite past-tense verb of the sentence. 'Halting' is wrong because the present participle requires an auxiliary verb to form a complete verb phrase and does not express a completed simple past action. 'Halts' is wrong because the third-person singular present simple implies a habitual or current action, not a completed past event.",category:"Grammar"},
  {id:"p5e103",question:"The updated guidelines _____ on the company intranet tomorrow.",options:["A) post","B) will be posted","C) are posting","D) posted"],answer:"B",explanation:"'Will be posted' is correct because the guidelines receive the action (passive voice) and 'tomorrow' signals a future time, requiring the future passive 'will be + past participle'. 'Post' is wrong because the base form alone cannot express future tense and does not reflect the passive relationship between the guidelines and the action. 'Are posting' is wrong because the present continuous active implies the guidelines themselves are doing the posting, which is illogical. 'Posted' is wrong because the simple past tense contradicts the future time marker 'tomorrow'.",category:"Grammar"},
  {id:"p5e104",question:"Each department _____ submit a budget proposal by November 1st.",options:["A) have to","B) has to","C) are to","D) were to"],answer:"B",explanation:"'Has to' is correct because 'each department' is a singular subject (each always takes a singular verb), requiring the third-person singular form 'has to' to express obligation. 'Have to' is wrong because 'have to' is used with plural subjects or with I/you, not with the singular 'each department'. 'Are to' is wrong because 'are' is a plural verb form and does not agree with the singular subject 'each department'. 'Were to' is wrong because it is the past plural conditional form, which contradicts the present obligation and the future deadline indicated by the sentence.",category:"Grammar"},
  {id:"p5e105",question:"The seminar _____ by more than 300 professionals last year.",options:["A) attends","B) attended","C) was attended","D) was attending"],answer:"C",explanation:"'Was attended' is correct because the seminar receives the action (it was attended by people), requiring the passive voice, and 'last year' signals the simple past tense, giving 'was + past participle'. 'Attends' is wrong because it is the active third-person singular present, which contradicts both the passive relationship and the past time marker. 'Attended' is wrong because the simple past active 'attended' would mean the seminar itself attended something, reversing the logical subject-action relationship. 'Was attending' is wrong because the past continuous passive would require 'was being attended', not 'was attending', which is the active continuous.",category:"Grammar"},
  {id:"p5e106",question:"Neither the manager nor the staff _____ aware of the change.",options:["A) was","B) were","C) is","D) are"],answer:"B",explanation:"'Were' is correct because in 'neither...nor' constructions the verb agrees with the nearest subject ('staff'), and 'staff' as a collective noun referring to a group of people takes a plural verb in business English, giving 'were'. 'Was' is wrong because 'was' treats 'staff' as a singular noun, but when 'staff' refers to a group of individuals, standard usage requires the plural form 'were'. 'Is' is wrong because it is the present-tense singular form, and it does not agree with the plural collective noun 'staff' as the nearer subject. 'Are' is wrong because it is the present-tense plural form, but the sentence describes a past situation and requires the past tense 'were'.",category:"Grammar"},
  {id:"p5e107",question:"Please ensure the data _____ backed up every night.",options:["A) is","B) are","C) were","D) be"],answer:"A",explanation:"'Is' is correct because in American business English, 'data' is increasingly treated as a singular collective noun, requiring the singular verb 'is', and 'is backed up' forms the passive voice for a present habitual requirement. 'Are' is wrong because while 'data' can take a plural verb in scientific or British English (as the plural of 'datum'), the singular 'is' is expected in standard TOEIC business contexts. 'Were' is wrong because it is the past tense, which does not match the habitual present instruction 'every night'. 'Be' is wrong because the base form 'be' cannot serve as the finite main verb of the clause; a conjugated form ('is' or 'are') is required.",category:"Grammar"},
  {id:"p5e108",question:"The team _____ hard before the client finally approved the design.",options:["A) worked","B) has worked","C) had worked","D) works"],answer:"C",explanation:"'Had worked' is correct because the past perfect is used to describe an action that was completed before another past action, and 'before the client approved' establishes that the working happened first in the past sequence. 'Worked' is wrong because the simple past places both events on the same timeline without showing which happened first; the past perfect 'had worked' is required to make clear that the working was completed before the approval. 'Has worked' is wrong because the present perfect refers to a past action with present relevance, not to an action that preceded another past event. 'Works' is wrong because it is the simple present, which contradicts the entire past-tense narrative of the sentence.",category:"Grammar"},
  {id:"p5e109",question:"By next year, the company _____ its overseas operations to five countries.",options:["A) expanded","B) has expanded","C) will have expanded","D) expands"],answer:"C",explanation:"'Will have expanded' is correct because the future perfect tense is used when describing an action that will be completed by a specific future time, and 'by next year' is the classic trigger for the future perfect. 'Expanded' is wrong because the simple past describes a completed past action, contradicting the future reference point 'by next year'. 'Has expanded' is wrong because the present perfect describes a past action with present relevance, not something that will be complete by a future date. 'Expands' is wrong because the simple present is used for habitual actions or scheduled events, not for actions that will be finished by a future point in time.",category:"Grammar"},
  {id:"p5e110",question:"The new inventory system _____ a significant amount of time for the warehouse team.",options:["A) saves","B) saved","C) is saved","D) saving"],answer:"A",explanation:"'Saves' is correct because the sentence describes a current, ongoing truth about what the system does, requiring the present simple tense, and 'saves' agrees with the singular subject 'system'. 'Saved' is wrong because the simple past implies the system no longer saves time, but the sentence presents it as a current fact. 'Is saved' is wrong because the passive 'is saved' would mean the system itself is being saved, which reverses the logical relationship. 'Saving' is wrong because the present participle requires an auxiliary verb (is saving) to form a complete verb phrase.",category:"Grammar"},
  {id:"p5e111",question:"The contract was signed _____ both parties last week.",options:["A) from","B) with","C) by","D) among"],answer:"C",explanation:"'By' is correct because in passive voice constructions, the agent (the person or party performing the action) is introduced by the preposition 'by', giving 'was signed by both parties'. 'From' is wrong because 'from' indicates origin or source, not the agent performing an action in a passive sentence. 'With' is wrong because 'with' indicates accompaniment or an instrument, not the responsible agent in a passive construction. 'Among' is wrong because 'among' describes relationships within a group of three or more, not the agent of a passive verb.",category:"Preposition"},
  {id:"p5e112",question:"Applications are accepted _____ the online portal only.",options:["A) through","B) over","C) from","D) at"],answer:"A",explanation:"'Through' is correct because it indicates the channel or medium by which something is transmitted or processed, making 'through the online portal' the standard expression for an electronic submission method. 'Over' is wrong because 'over the portal' is not idiomatic for describing an online submission system; 'over' is used for broadcasts or telephone (over the phone). 'From' is wrong because 'from' indicates the source or origin of something, not the channel through which applications are submitted. 'At' is wrong because 'at' marks a specific point or location, not the channel or medium for submitting applications.",category:"Preposition"},
  {id:"p5e113",question:"The new regulation comes _____ effect from January 1st.",options:["A) to","B) in","C) into","D) on"],answer:"C",explanation:"'Come into effect' is correct because it is a fixed idiomatic expression meaning to begin to be applied or enforced, and 'into' is the only preposition that forms this standard legal and business phrase. 'To' is wrong because 'come to effect' is not the established idiom; 'come to' typically means to regain consciousness or to amount to a total. 'In' is wrong because 'come in effect' is not standard English; 'in effect' means currently operative but 'come in effect' is not used as a phrase for becoming operative. 'On' is wrong because 'come on effect' is not a recognized expression in English.",category:"Preposition"},
  {id:"p5e114",question:"Please keep a copy of this receipt _____ your records.",options:["A) for","B) to","C) on","D) at"],answer:"A",explanation:"'For your records' is correct because 'for' indicates purpose or benefit, and 'for your records' is a fixed business expression meaning to keep a copy for future reference or documentation purposes. 'To' is wrong because 'to your records' is not a standard expression; 'to' indicates direction or a recipient, not the purpose of keeping a document. 'On' is wrong because 'on your records' would imply the receipt is placed on top of physical records, not stored for reference purposes. 'At' is wrong because 'at your records' is not a recognized expression in English for this purpose.",category:"Preposition"},
  {id:"p5e115",question:"The CEO will speak _____ behalf of the entire organization.",options:["A) from","B) in","C) on","D) at"],answer:"C",explanation:"'On behalf of' is correct because it is the fixed idiomatic expression meaning acting as a representative of someone or an organization, and 'on' is the required preposition. 'From' is wrong because 'from behalf of' is not a recognized English expression; 'from' indicates origin or source, not representation. 'In' is wrong because 'in behalf of' carries a different meaning (acting for the benefit of someone) rather than acting as a representative of an organization, so it does not fit the context of speaking as an official representative. 'At' is wrong because 'at behalf of' is not a recognized English expression.",category:"Preposition"},
  {id:"p5e116",question:"We were informed _____ the changes only this morning.",options:["A) for","B) about","C) from","D) with"],answer:"B",explanation:"'Informed about' is correct because the verb 'inform' takes the preposition 'about' when indicating the subject matter of the information given, as in 'informed about the changes'. 'For' is wrong because 'informed for' is not a standard verb-preposition collocation in English; 'for' indicates purpose or benefit. 'From' is wrong because 'informed from' is not a recognized construction; 'from' indicates a source of information but does not collocate with 'informed' in this way. 'With' is wrong because 'informed with' is not a standard expression; 'with' indicates accompaniment or means.",category:"Preposition"},
  {id:"p5e117",question:"The project was completed _____ schedule, saving us two weeks.",options:["A) on","B) in","C) ahead of","D) before"],answer:"C",explanation:"'Ahead of schedule' is correct because it is the fixed expression meaning earlier than the planned or expected time, and the result of saving two weeks confirms the project finished early. 'On schedule' is wrong because 'on schedule' means exactly as planned, with no time saved, which contradicts the detail about saving two weeks. 'In schedule' is wrong because 'in schedule' is not a recognized English expression for this meaning. 'Before schedule' is wrong because while 'before' can indicate earlier timing, the established idiomatic expression in business English for finishing early is 'ahead of schedule', not 'before schedule'.",category:"Preposition"},
  {id:"p5e118",question:"The team is divided _____ three groups for the workshop.",options:["A) to","B) in","C) into","D) among"],answer:"C",explanation:"'Divided into' is correct because 'divide into' is the fixed verb-preposition collocation used when something is split or separated into parts, giving 'divided into three groups'. 'To' is wrong because 'divided to' is not a recognized collocation; 'to' indicates direction or a recipient, not the result of splitting into parts. 'In' is wrong because 'divided in' is not standard English for this meaning; 'divide into' requires 'into' to show transformation from one entity into multiple parts. 'Among' is wrong because 'divided among' means distributed or shared among members (the work was divided among the team), not separated into distinct subgroups.",category:"Preposition"},
  {id:"p5e119",question:"Please note that parking is available _____ charge.",options:["A) free of","B) without of","C) no","D) lacking"],answer:"A",explanation:"'Free of charge' is correct because it is a fixed idiomatic expression meaning at no cost, and the full phrase 'available free of charge' is the standard way to indicate something costs nothing. 'Without of' is wrong because 'without of' is not grammatically correct in English; the preposition 'without' does not take a following 'of'. 'No' is wrong because 'available no charge' is not a grammatically complete or standard English expression. 'Lacking' is wrong because 'lacking' means missing or deficient in something, which does not idiomatically express the concept of being free of cost.",category:"Vocabulary"},
  {id:"p5e120",question:"The proposal was rejected _____ the grounds that it exceeded the budget.",options:["A) on","B) in","C) at","D) by"],answer:"A",explanation:"'On the grounds that' is correct because it is a fixed legal and formal expression meaning 'for the reason that', and 'on' is the required preposition in this phrase. 'In' is wrong because 'in the grounds that' is not a recognized English expression for stating reasons. 'At' is wrong because 'at the grounds that' is not a standard expression; 'at' marks specific points or times, not reasons. 'By' is wrong because 'by the grounds that' is not a recognized phrase; 'by' indicates means or the agent in a passive sentence.",category:"Preposition"},
  {id:"p5e121",question:"The company _____ a record $2 billion in revenue last quarter.",options:["A) posts","B) posted","C) post","D) posting"],answer:"B",explanation:"'Posted' is correct because the time marker 'last quarter' signals a completed past action, requiring the simple past tense, and 'post a record' is the standard business expression for reporting impressive financial results. 'Posts' is wrong because the third-person singular present contradicts the past time marker 'last quarter'. 'Post' is wrong because the base form alone cannot serve as the finite past-tense verb of the sentence. 'Posting' is wrong because the present participle requires an auxiliary verb to form a complete verb phrase and does not express a simple completed past action.",category:"Vocabulary"},
  {id:"p5e122",question:"She was _____ for her outstanding contribution to the project.",options:["A) recognized","B) recognize","C) recognition","D) recognizing"],answer:"A",explanation:"'Recognized' is correct because the passive past 'was + past participle' is needed to indicate that she received acknowledgment from others for her contribution. 'Recognize' is wrong because the base form cannot follow the auxiliary 'was' to form the passive; the past participle 'recognized' is required. 'Recognition' is wrong because it is a noun meaning acknowledgment, and a noun cannot follow 'was' to complete the passive verb phrase. 'Recognizing' is wrong because 'was recognizing' would form the past continuous active, implying she was the one doing the recognizing, which contradicts the meaning.",category:"Vocabulary"},
  {id:"p5e123",question:"The branch will _____ operations from its new location in April.",options:["A) resume","B) resuming","C) resumes","D) resumed"],answer:"A",explanation:"'Resume' is correct because after the modal 'will', the base form of the main verb is required, and 'resume operations' is the standard business expression for restarting activities. 'Resuming' is wrong because the present participle cannot directly follow a modal; 'will be resuming' would be needed for the future continuous. 'Resumes' is wrong because the third-person singular present form cannot follow a modal verb. 'Resumed' is wrong because the past tense or past participle cannot follow 'will' directly in an active sentence.",category:"Vocabulary"},
  {id:"p5e124",question:"We are required to _____ all safety procedures strictly.",options:["A) follow","B) following","C) followed","D) follows"],answer:"A",explanation:"'Follow' is correct because the structure 'required to' is followed by the base infinitive form, and 'follow procedures' is the standard expression for adhering to established processes. 'Following' is wrong because the present participle cannot follow the infinitive marker 'to'; the base form is required. 'Followed' is wrong because the past participle cannot follow 'to' as a standard active infinitive; it would need 'be' to form the passive (to be followed). 'Follows' is wrong because the third-person singular present form cannot follow the infinitive marker 'to'.",category:"Vocabulary"},
  {id:"p5e125",question:"The company _____ a new policy to limit business travel expenses.",options:["A) implements","B) has implemented","C) implement","D) implementing"],answer:"B",explanation:"'Has implemented' is correct because the present perfect is used for a recently completed action that is relevant to the current situation, indicating the policy is now in place. 'Implements' is wrong because the simple present describes a habitual or current ongoing action, not a recently completed change in company policy. 'Implement' is wrong because the base form cannot serve as the finite main verb of the sentence without an auxiliary for subject-verb agreement. 'Implementing' is wrong because the present participle requires an auxiliary verb to form a complete verb phrase.",category:"Vocabulary"},
  {id:"p5e126",question:"The product recall _____ a significant impact on consumer trust.",options:["A) have","B) having","C) had","D) has had"],answer:"D",explanation:"'Has had' is correct because the present perfect 'has had' describes a past event (the recall) whose effect on consumer trust continues to be relevant in the present. 'Have' is wrong because 'the product recall' is a singular subject requiring 'has', not the plural auxiliary 'have'. 'Having' is wrong because the present participle 'having' requires an auxiliary verb to form a complete verb phrase. 'Had' is wrong because the simple past 'had' would imply the impact is no longer relevant, whereas the present perfect connects the past action to the current state of consumer trust.",category:"Vocabulary"},
  {id:"p5e127",question:"The manager _____ a comprehensive plan to address the staffing shortage.",options:["A) drew up","B) drew in","C) drew out","D) drew on"],answer:"A",explanation:"'Drew up' is correct because 'draw up' is a phrasal verb meaning to prepare or draft a formal document or plan, making it the natural collocation with 'a comprehensive plan'. 'Drew in' is wrong because 'draw in' means to attract or involve someone, not to create or prepare a document. 'Drew out' is wrong because 'draw out' means to prolong or to extract something from someone, not to create a formal plan. 'Drew on' is wrong because 'draw on' means to make use of a resource or skill (draw on experience), not to prepare or write a plan.",category:"Vocabulary"},
  {id:"p5e128",question:"We _____ forward to meeting you at the industry conference.",options:["A) look","B) looking","C) looked","D) looks"],answer:"A",explanation:"'Look' is correct because 'we look forward to' is the standard present simple form of the fixed expression 'look forward to', used to express anticipation of a future event. 'Looking' is wrong because it is a present participle that cannot serve as the main verb of the sentence on its own; an auxiliary verb is required to form a complete verb phrase (e.g., 'we are looking forward to'). 'Looked' is wrong because the simple past implies the anticipation was in the past, but the conference is a future event being anticipated. 'Looks' is wrong because 'looks' is the third-person singular form, which does not agree with the first-person plural subject 'we'.",category:"Vocabulary"},
  {id:"p5e129",question:"The new software _____ the need for manual data entry.",options:["A) eliminates","B) elimination","C) eliminate","D) eliminating"],answer:"A",explanation:"'Eliminates' is correct because the subject 'the new software' is a singular third-person noun requiring the third-person singular present simple verb 'eliminates', describing a current ongoing fact. 'Elimination' is wrong because it is a noun referring to the act or process of removing something, and a noun cannot serve as the finite verb of the sentence. 'Eliminate' is wrong because the base form does not agree with the singular third-person subject; the sentence requires 'eliminates'. 'Eliminating' is wrong because the present participle requires an auxiliary verb to form a complete verb phrase.",category:"Vocabulary"},
  {id:"p5e130",question:"The team _____ extra hours to ensure the project was completed on time.",options:["A) put in","B) put out","C) put up","D) put on"],answer:"A",explanation:"'Put in extra hours' is correct because it is the standard phrasal verb meaning to work additional time beyond the regular schedule, and it collocates naturally with 'hours'. 'Put out' is wrong because 'put out' means to extinguish something, to inconvenience someone, or to publish, none of which relates to working extra time. 'Put up' is wrong because 'put up' means to erect something, to accommodate someone, or to tolerate, not to work additional hours. 'Put on' is wrong because 'put on' means to wear something, to stage an event, or to gain weight, not to contribute extra working hours.",category:"Vocabulary"},
  {id:"p5e131",question:"The survey revealed that most employees _____ flexible working hours.",options:["A) prefer","B) preferred","C) preferring","D) prefers"],answer:"A",explanation:"'Prefer' is correct because 'most employees' is a plural subject requiring the base form of the present simple verb, and the present simple is used here to state a general finding or current preference. 'Preferred' is wrong because the simple past implies the preference no longer exists, whereas the survey reveals a current ongoing attitude. 'Preferring' is wrong because the present participle requires an auxiliary verb to form a complete verb phrase in the main clause. 'Prefers' is wrong because 'prefers' is the third-person singular form, which does not agree with the plural subject 'most employees'.",category:"Grammar"},
  {id:"p5e132",question:"The company _____ the position after receiving 200 applications.",options:["A) fills","B) filled","C) is filling","D) has filled"],answer:"B",explanation:"'Filled' is correct because the sentence describes a completed past action — the position was filled after a concluded hiring process — requiring the simple past tense. 'Fills' is wrong because the simple present describes a habitual or current action, not a completed past hiring event. 'Is filling' is wrong because the present continuous describes an action currently in progress, but the position has already been filled. 'Has filled' is wrong because while the present perfect can describe recent completions, the specific completed sequence ('after receiving 200 applications') points to a simple past narrative.",category:"Grammar"},
  {id:"p5e133",question:"The invoice _____ paid within 14 days of the billing date.",options:["A) should be","B) should","C) is","D) be"],answer:"A",explanation:"'Should be paid' is correct because the invoice receives the action (passive voice) and 'should' expresses a modal obligation or expectation, giving the complete passive modal structure 'should be + past participle'. 'Should' alone is wrong because without 'be', the passive voice is incomplete; 'should paid' is not grammatically correct. 'Is' alone is wrong because 'is paid' forms the simple present passive, which implies a habitual fact rather than a payment obligation or instruction. 'Be' alone is wrong because the bare infinitive 'be paid' without a modal or auxiliary cannot serve as the finite predicate of the sentence.",category:"Grammar"},
  {id:"p5e134",question:"Please confirm _____ you will attend the event.",options:["A) that","B) which","C) what","D) how"],answer:"A",explanation:"'That' is correct because after the verb 'confirm', a 'that-clause' is used to introduce a statement of fact or information, and 'that' is the correct conjunction to introduce this content clause. 'Which' is wrong because 'which' introduces a relative clause that identifies or describes a noun, not a content clause reporting what someone is confirming. 'What' is wrong because 'what' introduces indirect questions or clauses with an open-ended unknown element (confirm what you need), whereas 'whether you will attend' or 'that you will attend' are the appropriate structures here. 'How' is wrong because 'how' introduces clauses about manner or degree, not statements of attendance.",category:"Grammar"},
  {id:"p5e135",question:"The manager asked the assistant to _____ the files alphabetically.",options:["A) arrange","B) arranges","C) arranged","D) arranging"],answer:"A",explanation:"'Arrange' is correct because in the structure 'ask + object + to-infinitive', the base form of the verb follows 'to', giving 'asked the assistant to arrange'. 'Arranges' is wrong because the third-person singular present form cannot follow the infinitive marker 'to'. 'Arranged' is wrong because the past tense or past participle cannot follow 'to' as a standard active infinitive. 'Arranging' is wrong because the present participle cannot follow the infinitive marker 'to'; the base form is required.",category:"Grammar"},
  {id:"p5e136",question:"She _____ the department very effectively since she was promoted.",options:["A) manages","B) managed","C) has managed","D) is managing"],answer:"C",explanation:"'Has managed' is correct because the present perfect is used for an action or situation that began in the past and continues to the present, and 'since she was promoted' signals the starting point of an ongoing situation. 'Manages' is wrong because the simple present describes a general fact without emphasizing continuity from a specific past point. 'Managed' is wrong because the simple past implies the managing has ended, but 'since' indicates the action is still ongoing. 'Is managing' is wrong because the present continuous describes a temporary or in-progress action without the connection to a past starting point that 'since' requires.",category:"Grammar"},
  {id:"p5e137",question:"The factory _____ to full capacity once the repairs are complete.",options:["A) returns","B) will return","C) returned","D) has returned"],answer:"B",explanation:"'Will return' is correct because the sentence describes a future event that will happen after a condition is met (once repairs are complete), and the future simple is the standard tense for this type of result clause. 'Returns' is wrong because the simple present in the result clause (as opposed to the condition clause) would not typically express a future result; the future simple 'will return' is expected. 'Returned' is wrong because the simple past contradicts the future orientation of the sentence. 'Has returned' is wrong because the present perfect describes a past action with present relevance, not a future result contingent on repairs being completed.",category:"Grammar"},
  {id:"p5e138",question:"All applicants _____ a copy of their academic transcripts.",options:["A) must submit","B) submitting","C) to submit","D) submits"],answer:"A",explanation:"'Must submit' is correct because the sentence expresses a mandatory requirement for all applicants, and 'must + base verb' is the standard structure for expressing strong obligation. 'Submitting' is wrong because the present participle alone cannot serve as the finite predicate of the sentence; it requires an auxiliary verb. 'To submit' is wrong because the to-infinitive alone cannot function as the finite predicate of the main clause; it requires a main verb before it. 'Submits' is wrong because 'submits' is the third-person singular form, which does not agree with the plural subject 'all applicants'.",category:"Grammar"},
  {id:"p5e139",question:"The product launch _____ for next spring, pending market approval.",options:["A) schedule","B) is scheduled","C) schedules","D) was scheduling"],answer:"B",explanation:"'Is scheduled for' is correct because the passive present 'is + past participle' is the standard way to express a planned future event, and 'scheduled for next spring' is the natural expression for a set date. 'Schedule' is wrong because the base form cannot serve as the finite verb of the sentence; a conjugated form is needed. 'Schedules' is wrong because the active third-person singular present implies the launch is scheduling something else rather than being planned. 'Was scheduling' is wrong because the past continuous active implies the launch was in the process of arranging something in the past, not that it is currently planned for the future.",category:"Grammar"},
  {id:"p5e140",question:"The manager _____ speaking with you about your promotion.",options:["A) look forward to","B) looks forward to","C) looking forward to","D) looked forward to"],answer:"B",explanation:"'Looks forward to' is correct because 'the manager' is a singular third-person subject requiring the third-person singular present simple form 'looks', and 'look forward to' is followed by the gerund 'speaking'. 'Look forward to' is wrong because the base form 'look' does not agree with the singular third-person subject 'the manager'; it requires 'looks'. 'Looking forward to' is wrong because the present participle requires an auxiliary verb such as 'is' to form the present continuous (is looking forward to). 'Looked forward to' is wrong because the simple past implies the anticipation was in the past and has ended, whereas a promotion discussion is presented as an upcoming event.",category:"Grammar"},
  {id:"p5e141",question:"The board _____ its quarterly meeting every third Friday.",options:["A) hold","B) holds","C) held","D) holding"],answer:"B",explanation:"'Holds' is correct because 'the board' is a singular collective noun subject requiring the third-person singular present simple form 'holds', and the present simple is used for regular, habitual events. 'Hold' is wrong because the base form does not agree with the singular subject 'the board'; the third-person singular 'holds' is required. 'Held' is wrong because the simple past describes a completed past action, whereas the frequency expression 'every third Friday' signals a habitual present action. 'Holding' is wrong because the present participle requires an auxiliary verb to form a complete verb phrase.",category:"Grammar"},
  {id:"p5e142",question:"Employees _____ to complete the survey before end of day.",options:["A) request","B) are requested","C) requesting","D) were requesting"],answer:"B",explanation:"'Are requested' is correct because the passive voice 'are + past participle' is used for formal announcements where the doer of the requesting is not the focus, and 'are requested to' is the standard formal phrase for official instructions to a group. 'Request' is wrong because the active base form implies employees are the ones making the request to someone else, which reverses the meaning. 'Requesting' is wrong because the present participle requires an auxiliary verb and implies employees are actively in the process of requesting something from others. 'Were requesting' is wrong because the past continuous implies employees were actively requesting something in the past, not that they have been officially asked to do a task now.",category:"Grammar"},
  {id:"p5e143",question:"The new printer _____ to replace the old one in Room 302.",options:["A) installs","B) is installed","C) was installed","D) has install"],answer:"C",explanation:"'Was installed' is correct because the sentence describes a completed past action (the printer was put in place) using the simple past passive 'was + past participle'. 'Installs' is wrong because the active third-person singular present implies the printer installs something else, which is illogical. 'Is installed' is wrong because the present passive describes a current or habitual state, not a specific completed past action. 'Has install' is wrong because 'has install' is not grammatically correct; the present perfect passive would require 'has been installed', with the past participle form.",category:"Grammar"},
  {id:"p5e144",question:"We _____ the pleasure of working with you for the past two years.",options:["A) have","B) have had","C) had","D) are having"],answer:"B",explanation:"'Have had' is correct because the present perfect 'have had' describes an experience or situation that began in the past and extends to the present, and 'for the past two years' confirms the ongoing nature of the relationship. 'Have' alone is wrong because 'have the pleasure' in simple present describes a general or current state rather than an experience that has been ongoing for a measured period. 'Had' is wrong because the simple past implies the working relationship has ended, whereas the present perfect with 'for the past two years' indicates it is still current. 'Are having' is wrong because the present continuous with 'have' in an experiential sense (have the pleasure) is not grammatical in standard English.",category:"Grammar"},
  {id:"p5e145",question:"The report should _____ no more than five pages.",options:["A) exceed","B) be exceeding","C) not exceed","D) have exceeded"],answer:"C",explanation:"'Should not exceed' is correct because the sentence sets a maximum limit on the report's length, and 'should not exceed' with the modal negative is the standard way to express a recommended upper limit or prohibition. 'Exceed' is wrong because 'should exceed' without the negative would mean the report is recommended to go over five pages, which is the opposite of the intended meaning. 'Be exceeding' is wrong because 'should be exceeding' forms the continuous, implying an ongoing action, whereas a page-limit rule is a simple constraint expressed with the base form. 'Have exceeded' is wrong because 'should have exceeded' implies the report was expected to go over five pages in the past, which contradicts the present instruction.",category:"Grammar"},
  {id:"p5e146",question:"Staff are encouraged to _____ ideas for improving workplace efficiency.",options:["A) share","B) sharing","C) shared","D) shares"],answer:"A",explanation:"'Share' is correct because in the structure 'encouraged to + infinitive', the base form of the verb is required after the infinitive marker 'to'. 'Sharing' is wrong because the present participle cannot follow the infinitive marker 'to'; the base form is required. 'Shared' is wrong because the past participle cannot follow 'to' as a standard active infinitive; it would need 'be' to form the passive (to be shared). 'Shares' is wrong because the third-person singular present form cannot follow the infinitive marker 'to'.",category:"Vocabulary"},
  {id:"p5e147",question:"The client has _____ all the necessary paperwork.",options:["A) sign","B) signed","C) signing","D) signs"],answer:"B",explanation:"'Signed' is correct because the present perfect 'has + past participle' is used to describe a recently completed action, and 'has signed' indicates the client completed the paperwork signing. 'Sign' is wrong because the base form cannot follow the auxiliary 'has' to form the present perfect; the past participle 'signed' is required. 'Signing' is wrong because 'has signing' is not grammatical; the present perfect continuous would need 'has been signing'. 'Signs' is wrong because the third-person singular present simple cannot follow the auxiliary 'has' in a perfect tense structure.",category:"Grammar"},
  {id:"p5e148",question:"The new employee will _____ the role of office coordinator.",options:["A) take on","B) take over","C) take up","D) take in"],answer:"A",explanation:"'Take on' is correct because 'take on a role' is the standard phrasal verb meaning to accept and begin a new responsibility or position. 'Take over' is wrong because 'take over' means to assume control of an organization or a position previously held by someone else, implying a takeover rather than simply accepting a new assignment. 'Take up' is wrong because 'take up' means to start a hobby or activity, or to occupy space or time, not to formally assume a professional role. 'Take in' is wrong because 'take in' means to absorb information, to deceive someone, or to accommodate, not to accept a professional role.",category:"Vocabulary"},
  {id:"p5e149",question:"The committee meets _____ a month to review progress.",options:["A) once","B) one","C) single","D) lone"],answer:"A",explanation:"'Once a month' is correct because it is the standard idiomatic expression for frequency meaning one time per month, and 'once' is the adverb of frequency used in time expressions like 'once a week' or 'once a year'. 'One' is wrong because 'one' is a number/adjective, and 'one a month' is not a grammatically standard frequency expression in English. 'Single' is wrong because 'single' is an adjective meaning one or unmarried, and 'single a month' is not a recognized frequency expression. 'Lone' is wrong because 'lone' means solitary or without companions, and 'lone a month' is not a meaningful or grammatical frequency expression.",category:"Vocabulary"},
  {id:"p5e150",question:"The renovation work _____ three weeks to complete.",options:["A) took","B) takes","C) taken","D) taking"],answer:"A",explanation:"'Took' is correct because the sentence describes a completed past event where the renovation required a certain amount of time, and 'take + time' in the simple past 'took' is the natural expression. 'Takes' is wrong because the simple present would imply the renovation is a habitual or ongoing process, not a completed past project. 'Taken' is wrong because the past participle 'taken' cannot serve as the finite verb of the sentence without an auxiliary verb (e.g., 'has taken'). 'Taking' is wrong because the present participle requires an auxiliary verb to form a complete verb phrase and cannot stand alone as the finite predicate.",category:"Grammar"}
];
